data.query:
mutation fulfillmentOrderReleaseHold($id: ID!, $externalId: String, $holdIds: [ID!]) {
    fulfillmentOrderReleaseHold(id: $id, externalId: $externalId, holdIds: $holdIds) {
        fulfillmentOrder {
            id
            status
            requestStatus
        }
        userErrors {
            field
            message
            code
        }
    }
}
